game.js

```javascript
class Block {
    constructor(color, level) {
        this.color = color;
        this.level = level;
    }
}

class Game {
    constructor() {
        this.board = Array.from({ length: 5 }, () => Array(5).fill(null));
        this.generateBlocks();
        this.renderBoard();
    }

    generateBlocks() {
        const blocks = [
            ...Array(10).fill(new Block("yellow", 1)),
            ...Array(9).fill(new Block("blue", 1)),
            ...Array(2).fill(new Block("blue", 2)),
            ...Array(4).fill(new Block("red", 1)),
        ];

        while (blocks.length) {
            const randomIndex = Math.floor(Math.random() * blocks.length);
            const block = blocks.splice(randomIndex, 1)[0];
            let placed = false;

            while (!placed) {
                const i = Math.floor(Math.random() * 5);
                const j = Math.floor(Math.random() * 5);

                if (!this.board[i][j]) {
                    this.board[i][j] = block;
                    placed = true;
                }
            }
        }
    }

    renderBoard() {
        const gameBoard = document.getElementById("game-board");
        gameBoard.innerHTML = "";

        for (let i = 0; i < 5; i++) {
            for (let j = 0; j < 5; j++) {
                const box = document.createElement("div");
                box.classList.add("box");
                const block = this.board[i][j];

                if (block) {
                    box.classList.add(block.color);
                    box.textContent = block.level;
                }

                gameBoard.appendChild(box);
            }
        }
    }
}

// Initialize game
new Game();
```

这是一个基本的游戏实现，其中包括渲染和生成地图、蓝色、黄色和红色方块。然而，还有很多功能需要实现，例如移动、合并和消除逻辑。

