            background-color: yellow;
        }
        .blue {
            background-color: deepskyblue;
        }
        .red {
            background-color: crimson;
        }
    </style>
</head>
<body>
    <table id="game-board"></table>
    <script>
        class Block {
            constructor(color, level) {
                this.color = color;
                this.level = level;
            }
        }

        class Game {
            constructor() {
                this.board = Array.from({ length: 5 }, () => Array(5).fill(null));
                this.gameBoardElement = document.getElementById("game-board");
                this.generateBlocks();
                this.renderBoard();
            }

            generateBlocks() {
                const blocks = [
                    ...Array(10).fill(new Block("yellow", 1)),
                    ...Array(9).fill(new Block("blue", 1)),
                    ...Array(2).fill(new Block("blue", 2)),
                    ...Array(4).fill(new Block("red", 1)),
                ];

                while (blocks.length) {
                    const randomIndex = Math.floor(Math.random() * blocks.length);
                    const block = blocks.splice(randomIndex, 1)[0];
                    let placed = false;

                    while (!placed) {
                        const i = Math.floor(Math.random() * 5);
                        const j = Math.floor(Math.random() * 5);

                        if (!this.board[i][j]) {
                            this.board[i][j] = block;
                            placed = true;
                        }
                    }
                }
            }

            renderBoard() {
                this.gameBoardElement.innerHTML = "";
                const fragment = document.createDocumentFragment();

                for (let i = 0; i < 5; i++) {
                    const row = document.createElement("tr");
                    for (let j = 0; j < 5; j++) {
                        const cell = document.createElement("td");
                        const block = this.board[i][j];

                        if (block) {
                            cell.classList.add(block.color);
                            cell.textContent = block.level;
                        }

                        row.appendChild(cell);
                    }
                    fragment.appendChild(row);
                }

                this.gameBoardElement.appendChild(fragment);
            }
        }

        // Initialize game
        new Game();
    </script>
</body>
</html>
```

